export const fetchCryptoPrices = async (ids: string[]): Promise<CryptoData[]> => {
  if (ids.length === 0) return [];

  try {
    const idString = ids.join(',');
    const response = await fetch(`https://api.coincap.io/v2/assets?ids=${idString}`);

    if (!response.ok) throw new Error("Erro API Cripto");

    const json = await response.json();

    return json.data.map((asset: any) => ({
      id: asset.id,
      symbol: asset.symbol,
      name: asset.name,
      priceUsd: parseFloat(asset.priceUsd),
      changePercent24Hr: parseFloat(asset.changePercent24Hr)
    }));
  } catch (error) {
    console.error("Falha ao buscar criptos:", error);
    return [];
  }
};

