import React, { useEffect, useState } from 'react';
import { X, Settings, Bell, MapPin, ToggleLeft, ToggleRight, LayoutDashboard, Mail, Calendar, Plus, Trash2, Key, Newspaper, Hash, ArrowUp, ArrowDown, ExternalLink, AlertTriangle, Bitcoin } from 'lucide-react';
import { DashboardPrefs } from '../types';

interface ConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
  preferences: DashboardPrefs;
  onTogglePreference: (key: keyof DashboardPrefs) => void;
  onReorderDashboard?: (newOrder: string[]) => void;
  onUpdateApiKey: (key: string) => void;
  notificationsEnabled: boolean;
  onToggleNotifications: () => void;
  locationEnabled: boolean;
  onToggleLocation: () => void;
  calendarIds?: string[];
  onAddCalendar?: (id: string) => void;
  onRemoveCalendar?: (id: string) => void;
  onAddNewsTopic?: (topic: string) => void;
  onRemoveNewsTopic?: (topic: string) => void;
  onUpdateCryptoIds?: (ids: string[]) => void;
}

const ConfigModal: React.FC<ConfigModalProps> = ({ 
    isOpen, onClose, 
    preferences, onTogglePreference, onReorderDashboard, onUpdateApiKey,
    notificationsEnabled, onToggleNotifications,
    locationEnabled, onToggleLocation,
    calendarIds = [], onAddCalendar, onRemoveCalendar,
    onAddNewsTopic, onRemoveNewsTopic,
    onUpdateCryptoIds
}) => {

  const [isVisible, setIsVisible] = useState(false);
  const [newCalendarInput, setNewCalendarInput] = useState('');
  const [newTopicInput, setNewTopicInput] = useState('');
  const [newCryptoInput, setNewCryptoInput] = useState('');
  const [apiKeyInput, setApiKeyInput] = useState(preferences.googleApiKey || '');
  const [apiKeyWarning, setApiKeyWarning] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      setIsVisible(true);
      document.body.style.overflow = 'hidden';
      setApiKeyInput(preferences.googleApiKey || '');
      setApiKeyWarning(null);
    } else {
      const timer = setTimeout(() => setIsVisible(false), 300);
      document.body.style.overflow = 'unset';
      return () => clearTimeout(timer);
    }
  }, [isOpen, preferences.googleApiKey]);

  const validateApiKey = (key: string) => {
      const trimmed = key.trim();
      if (trimmed.length > 0) {
          if (!trimmed.startsWith('AIza')) {
              setApiKeyWarning("Isso não parece uma API Key válida.");
          } else {
              setApiKeyWarning(null);
          }
      } else {
          setApiKeyWarning(null);
      }
      setApiKeyInput(trimmed);
  };

  const handleSave = () => {
    onUpdateApiKey(apiKeyInput.trim());
    onClose();
  };

  const handleAddTopic = () => {
    if (newTopicInput.trim() && onAddNewsTopic) {
        onAddNewsTopic(newTopicInput.trim());
        setNewTopicInput('');
    }
  };

  const handleAddCrypto = () => {
    if (newCryptoInput.trim() && onUpdateCryptoIds) {
      const cleanId = newCryptoInput.trim().toLowerCase().replace(/\s+/g, '-');
      const current = preferences.cryptoIds || [];
      if (!current.includes(cleanId)) {
        onUpdateCryptoIds([...current, cleanId]);
        setNewCryptoInput('');
      }
    }
  };

  const handleRemoveCrypto = (id: string) => {
    if (onUpdateCryptoIds) {
      onUpdateCryptoIds((preferences.cryptoIds || []).filter(c => c !== id));
    }
  };

  const extractCalendarId = (input: string): string | null => {
    if (!input || !input.trim()) return null;
    let cleaned = input.trim();
    const emailMatch = cleaned.match(/([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9._-]+)/);
    if (emailMatch && emailMatch[1]) return emailMatch[1];
    return cleaned;
  };

  const handleAddCalendar = () => {
    if (!newCalendarInput || !onAddCalendar) return;
    const extractedId = extractCalendarId(newCalendarInput);
    if (extractedId) {
       onAddCalendar(extractedId);
       setNewCalendarInput('');
    }
  };

  const moveItem = (index: number, direction: 'up' | 'down') => {
      if (!onReorderDashboard || !preferences.dashboardOrder) return;
      const newOrder = [...preferences.dashboardOrder];
      if (direction === 'up') {
          if (index === 0) return;
          [newOrder[index - 1], newOrder[index]] = [newOrder[index], newOrder[index - 1]];
      } else {
          if (index === newOrder.length - 1) return;
          [newOrder[index + 1], newOrder[index]] = [newOrder[index], newOrder[index + 1]];
      }
      onReorderDashboard(newOrder);
  };

  if (!isVisible && !isOpen) return null;

  const currentOrder = preferences.dashboardOrder || ['insight', 'sites_list', 'shortcuts', 'news', 'weather', 'crypto', 'notifications'];

  const blockNames: Record<string, string> = {
      insight: 'Insight do Dia',
      news: 'Destaques Notícias',
      weather: 'Clima',
      crypto: 'Criptomoedas (Quadrados)',
      shortcuts: 'Atalhos (Grade)',
      sites_list: 'Lista de Sites',
      notifications: 'Botão Notificações'
  };

  const ToggleItem = ({ label, icon: Icon, checked, onChange, description }: any) => (
    <div className="flex items-center justify-between p-3 bg-slate-900/50 rounded-xl border border-slate-800">
        <div className="flex items-center gap-3">
            <div className={`p-2 rounded-lg ${checked ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800 text-slate-500'}`}>
                <Icon className="w-5 h-5" />
            </div>
            <div>
                <p className="font-medium text-sm text-slate-200">{label}</p>
                {description && <p className="text-[10px] text-slate-500">{description}</p>}
            </div>
        </div>
        <button onClick={onChange} className="text-slate-300 hover:text-white transition-colors">
            {checked ? <ToggleRight className="w-8 h-8 text-blue-500" /> : <ToggleLeft className="w-8 h-8 text-slate-600" />}
        </button>
    </div>
  );

  return (
    <div className="fixed inset-0 z-[100] flex justify-end">
      <div 
        className={`absolute inset-0 bg-slate-900/80 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
        onClick={onClose}
      />

      <div 
        className={`relative w-[90%] max-w-[380px] h-full bg-slate-800 border-l border-slate-700 shadow-2xl flex flex-col transform transition-transform duration-300 ease-out pt-safe-area ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
      >
        <div className="p-5 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <Settings className="w-5 h-5 text-slate-300" />
                <span className="font-bold text-lg text-slate-100">Configurações</span>
            </div>
            <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-full hover:bg-slate-700 transition-colors">
                <X className="w-6 h-6" />
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-5 space-y-6">

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Credenciais</h3>
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                    <div className="flex items-center gap-2 mb-2">
                        <Key className="w-4 h-4 text-amber-400" />
                        <span className="text-xs font-bold text-slate-300">Google API Key</span>
                    </div>
                    <input 
                        type="text" 
                        value={apiKeyInput}
                        onChange={(e) => validateApiKey(e.target.value)}
                        placeholder="Cole sua chave AIza..."
                        className={`w-full bg-slate-950 border rounded-lg px-3 py-2 text-xs text-slate-200 outline-none focus:border-amber-500 ${apiKeyWarning ? 'border-rose-500/50 focus:border-rose-500' : 'border-slate-700'}`}
                    />
                    {apiKeyWarning && <p className="text-rose-400 text-[10px] mt-1">{apiKeyWarning}</p>}
                </div>
            </div>

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Layout Dashboard</h3>
                <div className="bg-slate-900/30 rounded-xl border border-slate-800 overflow-hidden">
                    {currentOrder.filter(id => id !== 'notifications').map((id, index) => (
                        <div key={id} className="flex items-center justify-between p-3 border-b border-slate-800/50 last:border-0">
                            <span className="text-sm font-medium text-slate-300">{blockNames[id] || id}</span>
                            <div className="flex gap-1">
                                <button onClick={() => moveItem(currentOrder.indexOf(id), 'up')} disabled={currentOrder.indexOf(id) === 0} className="p-1 text-slate-500 hover:text-white disabled:opacity-20"><ArrowUp className="w-4 h-4" /></button>
                                <button onClick={() => moveItem(currentOrder.indexOf(id), 'down')} disabled={currentOrder.indexOf(id) === currentOrder.length - 1} className="p-1 text-slate-500 hover:text-white disabled:opacity-20"><ArrowDown className="w-4 h-4" /></button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Criptomoedas</h3>
                <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                    <div className="flex gap-2 mb-3">
                        <input 
                            type="text" 
                            value={newCryptoInput}
                            onChange={(e) => setNewCryptoInput(e.target.value)}
                            placeholder="Ex: solana, cardano..."
                            className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-xs text-slate-200 outline-none focus:border-orange-500"
                        />
                        <button onClick={handleAddCrypto} className="bg-orange-600 text-white p-2 rounded-lg"><Plus className="w-4 h-4" /></button>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {preferences.cryptoIds && preferences.cryptoIds.map(id => (
                            <div key={id} className="flex items-center gap-1 bg-slate-800 px-2 py-1 rounded-full border border-slate-700/50">
                                <span className="text-[10px] text-slate-300 font-bold uppercase">{id}</span>
                                <button onClick={() => handleRemoveCrypto(id)} className="text-slate-500 hover:text-rose-400"><X className="w-3 h-3" /></button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Visibilidade</h3>
                <ToggleItem label="Criptomoedas" icon={Bitcoin} checked={preferences.showCrypto} onChange={() => onTogglePreference('showCrypto')} />
                <ToggleItem label="Sites" icon={Globe} checked={preferences.showSites} onChange={() => onTogglePreference('showSites')} />
                <ToggleItem label="Trello" icon={Trello} checked={preferences.showTrello} onChange={() => onTogglePreference('showTrello')} />
                <ToggleItem label="E-mails" icon={Mail} checked={preferences.showGoogle} onChange={() => onTogglePreference('showGoogle')} />
                <ToggleItem label="Clima" icon={MapPin} checked={preferences.showWeather} onChange={() => onTogglePreference('showWeather')} />
            </div>

        </div>

        <div className="p-4 border-t border-slate-700 bg-slate-800/50 text-center pb-safe-area">
            <button onClick={handleSave} className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl shadow-lg shadow-blue-900/20">
                Salvar Alterações
            </button>
        </div>
      </div>
    </div>
  );
};

