import React, { useEffect, useState } from 'react';
import { X, Settings, MapPin, ToggleLeft, ToggleRight, Mail, Plus, Bitcoin, Globe, Trello, ArrowUp, ArrowDown } from 'lucide-react';
import { DashboardPrefs } from '../types';

interface ConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
  preferences: DashboardPrefs;
  onTogglePreference: (key: keyof DashboardPrefs) => void;
  onReorderDashboard?: (newOrder: string[]) => void;
  onUpdateApiKey: (key: string) => void;
  notificationsEnabled: boolean;
  onToggleNotifications: () => void;
  locationEnabled: boolean;
  onToggleLocation: () => void;
  calendarIds?: string[];
  onAddCalendar?: (id: string) => void;
  onRemoveCalendar?: (id: string) => void;
  onAddNewsTopic?: (topic: string) => void;
  onRemoveNewsTopic?: (topic: string) => void;
  onUpdateCryptoIds?: (ids: string[]) => void;
}

const ConfigModal: React.FC<ConfigModalProps> = ({ 
    isOpen, onClose, 
    preferences, onTogglePreference, onReorderDashboard,
    locationEnabled, onToggleLocation,
    onUpdateCryptoIds
}) => {

  const [isVisible, setIsVisible] = useState(false);
  const [newCryptoInput, setNewCryptoInput] = useState('');

  useEffect(() => {
    if (isOpen) {
      setIsVisible(true);
      document.body.style.overflow = 'hidden';
    } else {
      const timer = setTimeout(() => setIsVisible(false), 300);
      document.body.style.overflow = 'unset';
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  const handleAddCrypto = () => {
    if (newCryptoInput.trim() && onUpdateCryptoIds) {
      const cleanId = newCryptoInput.trim().toLowerCase().replace(/\s+/g, '-');
      const current = preferences.cryptoIds || [];
      if (!current.includes(cleanId)) {
        onUpdateCryptoIds([...current, cleanId]);
        setNewCryptoInput('');
      }
    }
  };

  const handleRemoveCrypto = (id: string) => {
    if (onUpdateCryptoIds) {
      onUpdateCryptoIds((preferences.cryptoIds || []).filter(c => c !== id));
    }
  };

  const moveItem = (index: number, direction: 'up' | 'down') => {
      if (!onReorderDashboard || !preferences.dashboardOrder) return;
      const newOrder = [...preferences.dashboardOrder];
      if (direction === 'up') {
          if (index === 0) return;
          [newOrder[index - 1], newOrder[index]] = [newOrder[index], newOrder[index - 1]];
      } else {
          if (index === newOrder.length - 1) return;
          [newOrder[index + 1], newOrder[index]] = [newOrder[index], newOrder[index + 1]];
      }
      onReorderDashboard(newOrder);
  };

  if (!isVisible && !isOpen) return null;

  const currentOrder = preferences.dashboardOrder || ['insight', 'sites_list', 'shortcuts', 'news', 'weather', 'crypto', 'notifications'];

  const blockNames: Record<string, string> = {
      insight: 'Insight do Dia',
      news: 'Notícias',
      weather: 'Clima',
      crypto: 'Criptomoedas',
      shortcuts: 'Atalhos',
      sites_list: 'Status Sites',
      notifications: 'Notificações'
  };

  const ToggleItem = ({ label, icon: Icon, checked, onChange }: any) => (
    <div className="flex items-center justify-between p-3 bg-slate-900/50 rounded-xl border border-slate-800">
        <div className="flex items-center gap-3">
            <div className={`p-2 rounded-lg ${checked ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800 text-slate-500'}`}>
                <Icon className="w-5 h-5" />
            </div>
            <p className="font-medium text-sm text-slate-200">{label}</p>
        </div>
        <button onClick={onChange}>
            {checked ? <ToggleRight className="w-8 h-8 text-blue-500" /> : <ToggleLeft className="w-8 h-8 text-slate-600" />}
        </button>
    </div>
  );

  return (
    <div className="fixed inset-0 z-[100] flex justify-end">
      <div className={`absolute inset-0 bg-slate-900/80 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`} onClick={onClose} />
      <div className={`relative w-[90%] max-w-[380px] h-full bg-slate-800 border-l border-slate-700 shadow-2xl flex flex-col transform transition-transform duration-300 ease-out pt-safe-area ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-5 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <Settings className="w-5 h-5 text-slate-300" />
                <span className="font-bold text-lg text-slate-100">Configurações</span>
            </div>
            <button onClick={onClose} className="p-2 text-slate-400 hover:text-white"><X className="w-6 h-6" /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-5 space-y-6">
            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Ordem Dashboard</h3>
                <div className="bg-slate-900/30 rounded-xl border border-slate-800 overflow-hidden">
                    {currentOrder.map((id, index) => (
                        <div key={id} className="flex items-center justify-between p-3 border-b border-slate-800 last:border-0">
                            <span className="text-sm font-medium text-slate-300">{blockNames[id] || id}</span>
                            <div className="flex gap-1">
                                <button onClick={() => moveItem(index, 'up')} disabled={index === 0} className="p-1 text-slate-500 disabled:opacity-20"><ArrowUp className="w-4 h-4" /></button>
                                <button onClick={() => moveItem(index, 'down')} disabled={index === currentOrder.length - 1} className="p-1 text-slate-500 disabled:opacity-20"><ArrowDown className="w-4 h-4" /></button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Criptomoedas</h3>
                <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                    <div className="flex gap-2 mb-3">
                        <input type="text" value={newCryptoInput} onChange={(e) => setNewCryptoInput(e.target.value)} placeholder="ID (ex: solana)" className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-xs text-slate-200 outline-none" />
                        <button onClick={handleAddCrypto} className="bg-orange-600 text-white p-2 rounded-lg"><Plus className="w-4 h-4" /></button>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {preferences.cryptoIds.map(id => (
                            <div key={id} className="flex items-center gap-1 bg-slate-800 px-2 py-1 rounded-full border border-slate-700">
                                <span className="text-[10px] text-slate-300 font-bold uppercase">{id}</span>
                                <button onClick={() => handleRemoveCrypto(id)}><X className="w-3 h-3 text-rose-400" /></button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="space-y-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider px-1">Visibilidade</h3>
                <ToggleItem label="Criptomoedas" icon={Bitcoin} checked={preferences.showCrypto} onChange={() => onTogglePreference('showCrypto')} />
                <ToggleItem label="Sites" icon={Globe} checked={preferences.showSites} onChange={() => onTogglePreference('showSites')} />
                <ToggleItem label="Trello" icon={Trello} checked={preferences.showTrello} onChange={() => onTogglePreference('showTrello')} />
                <ToggleItem label="E-mails" icon={Mail} checked={preferences.showGoogle} onChange={() => onTogglePreference('showGoogle')} />
                <ToggleItem label="Clima" icon={MapPin} checked={preferences.showWeather} onChange={() => onTogglePreference('showWeather')} />
            </div>
        </div>

        <div className="p-4 border-t border-slate-700 bg-slate-800/50">
            <button onClick={onClose} className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl">Salvar</button>
        </div>
      </div>
    </div>
  );
};

