      <SideMenu isOpen={isSideMenuOpen} onClose={() => setIsSideMenuOpen(false)} onNavigate={(v) => setCurrentView(v as ViewState)} onGenerateInsight={handleGenerateInsight} badges={{ forms: forms.filter(f => !f.isRead).length, emails: emails.filter(e => e.isUnread).length, trello: trelloCards.length }} />
      <ConfigModal isOpen={isConfigModalOpen} onClose={() => setIsConfigModalOpen(false)} preferences={dashPrefs} onTogglePreference={(k) => setDashPrefs(p => ({ ...p, [k]: !p[k as keyof typeof p] }))} onUpdateApiKey={() => {}} notificationsEnabled={notifPermission === 'granted'} onToggleNotifications={() => {}} locationEnabled={!weatherPermissionDenied} onToggleLocation={loadWeather} onUpdateCryptoIds={(ids) => setDashPrefs(p => ({ ...p, cryptoIds: ids }))} onReorderDashboard={(o) => setDashPrefs(p => ({ ...p, dashboardOrder: o }))} />
