      <ConfigModal isOpen={isConfigModalOpen} onClose={() => setIsConfigModalOpen(false)} preferences={dashPrefs} onTogglePreference={(k) => setDashPrefs(p => ({ ...p, [k]: !p[k as keyof typeof p] }))} onUpdateApiKey={() => {}} notificationsEnabled={notifPermission === 'granted'} onToggleNotifications={() => {}} locationEnabled={!weatherPermissionDenied} onToggleLocation={loadWeather} onReorderDashboard={(o) => setDashPrefs(p => ({ ...p, dashboardOrder: o }))} />
