  const [trelloKey, setTrelloKey] = usePersistedState<string>('monitor_trello_key_v7', TRELLO_API_KEY);
  const [trelloToken, setTrelloToken] = usePersistedState<string>('monitor_trello_token_v7', TRELLO_TOKEN);
  const [trelloListIds, setTrelloListIds] = usePersistedState<string[]>('monitor_trello_lists_v7', []);
  const [trelloCards, setTrelloCards] = useState<TrelloCard[]>([]);

  const sitesRef = useRef<SiteConfig[]>(DEFAULT_SITES);

  useEffect(() => { sitesRef.current = sites; }, [sites]);

  const loadWeather = useCallback(() => {
    if (!('geolocation' in navigator)) return;
    setLoadingWeather(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const weatherData = await fetchWeather(latitude, longitude);
          const locationName = await fetchLocationName(latitude, longitude);
          if (weatherData) setWeather({ ...weatherData, locationName });
        } catch (e) {
          console.error("Erro clima:", e);
        } finally {
          setLoadingWeather(false);
        }
      },
      (error) => {
        setLoadingWeather(false);
        if (error.code === error.PERMISSION_DENIED) setWeatherPermissionDenied(true);
      }
    );
  }, []);

  const loadNews = async (force: boolean = false) => {
    if (!force && newsArticles.length > 0 && (Date.now() - lastNewsFetch < 3600000)) return;
    setIsLoadingNews(true);
    try {
        const newArticles = await fetchNewsWithAI(dashPrefs.newsTopics);
        if (newArticles.length > 0) {
            setNewsArticles(newArticles);
            setLastNewsFetch(Date.now());
            setNewsError(null); 
        }
    } catch (e: any) {
        setNewsError(e.message || "Falha ao carregar notícias");
    } finally {
        setIsLoadingNews(false);
    }
  };

  const updateCalendar = async () => {
    if (!googleToken) return;
    setIsLoadingCalendar(true);
    try {
        const events = await fetchCalendarEvents({ token: googleToken, apiKey: '' }, calendarIds);
        setCalendarEvents(events);
    } catch (e) {
        console.error("Erro calendário:", e);
    } finally {
        setIsLoadingCalendar(false);
    }
  };

  const fetchTrelloCards = async () => {
    if (!trelloKey || !trelloToken || !trelloListIds.length) return;
    try {
      const promises = trelloListIds.map(async listId => await fetchCardsFromList(trelloKey, trelloToken, listId));
      const results = await Promise.all(promises);
      setTrelloCards(results.flat().sort((a, b) => b.dateLastActivity.getTime() - a.dateLastActivity.getTime()));
    } catch (e) {
      console.error("Erro trello:", e);
    }
  };

  const checkAllSites = useCallback(async () => {
    const results = await Promise.all(sitesRef.current.map(async site => {
      try {
        const stats = await fetchSiteStats(site);
        if (stats) return { ...site, status: SiteStatus.ONLINE, lastChecked: new Date(), onlineUsers: stats.online, monthlyVisitors: stats.monthly };
        return { ...site, status: SiteStatus.ONLINE, lastChecked: new Date() };
      } catch (e) {
        return { ...site, status: SiteStatus.OFFLINE, lastChecked: new Date() };
      }
    }));
    setSites(results);
  }, []);

  const syncForms = async () => {
    setIsLoadingForms(true);
    try {
      const results = await Promise.all(sitesRef.current.map(site => fetchFormsFromWP(site)));
      setForms(results.flat());
    } catch (e) {
      console.error("Erro forms:", e);
    } finally {
      setIsLoadingForms(false);
    }
  };

  const handleGenerateInsight = async () => {
    setIsLoadingInsight(true);
    setInsightResult(null); 
    setInsightError(null);
    try {
        const context = {
            sites: sites.map(s => `${s.name}: ${s.status}`),
            forms: forms.filter(f => !f.isRead).slice(0, 3).map(f => `${f.senderName}: ${f.message.substring(0, 30)}`),
            emails: emails.filter(e => e.isUnread).slice(0, 5).map(e => e.subject),
            trello: trelloCards.length,
            weather: weather ? `${weather.current.temp}°C, ${getWeatherInfo(weather.current.code).label}` : "Clima desconhecido"
        };
        const result = await generateDashboardInsight(context); 
        setInsightResult(result);
    } catch (error: any) {
        setInsightError(error.message || "Erro ao gerar insight.");
    } finally {
        setIsLoadingInsight(false);
    }
  };

  useEffect(() => {
    loadNews();
    if (dashPrefs.showWeather) loadWeather();
    checkAllSites();
    syncForms();
    if (googleToken) updateCalendar();
    if (trelloKey && trelloToken) fetchTrelloCards();

    const interval = setInterval(() => {
        checkAllSites();
        syncForms();
    }, 60000);
    return () => clearInterval(interval);
  }, [checkAllSites, syncForms, googleToken, trelloKey, trelloToken, dashPrefs.showWeather, loadWeather]);

  const renderDashboard = () => {
    const blocks: Record<string, React.ReactElement | null> = {
      insight: (
        <div key="insight" onClick={() => !isLoadingInsight && handleGenerateInsight()} className="bg-gradient-to-r from-indigo-900/80 to-slate-800 p-4 rounded-2xl border border-indigo-500/20 shadow-lg cursor-pointer">
            <div className="flex justify-between items-center mb-2">
                <div className="flex items-center gap-2">
                    <Sparkles className="w-4 h-4 text-yellow-300" />
                    <h3 className="font-bold text-slate-100 text-xs uppercase">Insight do Dia</h3>
                </div>
                {isLoadingInsight && <RefreshCw className="w-3 h-3 text-indigo-300 animate-spin" />}
            </div>
            {insightError ? <p className="text-xs text-rose-400">{insightError}</p> : insightResult ? <p className="text-xs text-slate-300 leading-relaxed whitespace-pre-line">{insightResult}</p> : <p className="text-xs text-slate-400 italic">Toque para gerar resumo com IA.</p>}
        </div>
      ),
      news: <NewsWidget key="news" articles={newsArticles} isLoading={isLoadingNews} onNavigate={() => setCurrentView(ViewState.NEWS)} />,
      weather: weather ? <WeatherWidget key="weather" weather={weather} loading={loadingWeather} permissionDenied={weatherPermissionDenied} onRequestPermission={loadWeather} /> : null,
      shortcuts: (
        <div key="shortcuts" className="grid grid-cols-2 gap-4">
          <div onClick={() => {setCurrentView(ViewState.WEBSITES); setWebsiteSubTab('status');}} className="bg-slate-800 p-4 rounded-2xl border border-slate-700 shadow-sm cursor-pointer active:scale-95">
            <div className="flex items-center gap-2 mb-2 text-brand-400"><Globe className="w-4 h-4" /><span className="text-xs font-semibold">SITES</span></div>
            <div className="text-2xl font-bold text-slate-100">{sites.filter(s => s.status === SiteStatus.ONLINE).length}/{sites.length}</div>
          </div>
          <div onClick={() => {setCurrentView(ViewState.WEBSITES); setWebsiteSubTab('forms');}} className="bg-slate-800 p-4 rounded-2xl border border-slate-700 shadow-sm cursor-pointer active:scale-95">
            <div className="flex items-center gap-2 mb-2 text-blue-400"><MessageSquareText className="w-4 h-4" /><span className="text-xs font-semibold">FORMS</span></div>
            <div className="text-2xl font-bold text-slate-100">{forms.filter(f => !f.isRead).length}</div>
          </div>
        </div>
      ),
      sites_list: dashPrefs.showSites ? (
          <div key="sites_list" className="mb-6">
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 px-1">Monitoramento</h3>
            {sites.map(site => <MonitorCard key={site.id} site={site} onRefresh={() => {}} minimal={true} />)}
          </div>
      ) : null
    };

    const currentOrder = dashPrefs.dashboardOrder || ['insight', 'sites_list', 'shortcuts', 'news', 'weather'];

    return (
      <div className="space-y-6 animate-fade-in pt-4 pb-32">
        {currentOrder.map(id => blocks[id] || null)}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-brand-900 text-slate-200 font-sans">
      <header className="fixed top-0 w-full z-40 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 pt-safe-area shadow-sm">
         <div className="flex justify-between items-center px-4 h-16 max-w-md mx-auto">
             <button onClick={() => setIsSideMenuOpen(true)} className="p-2 -ml-2 text-slate-400 hover:text-white"><Menu className="w-6 h-6" /></button>
             <div className="flex items-center justify-center cursor-pointer" onClick={() => setCurrentView(ViewState.DASHBOARD)}>
                <img src="https://tidas.com.br/wp-content/uploads/2025/08/logo_tidas_rodan2.svg" alt="Tidas" className="h-[1.6rem] w-auto" />
             </div>
             <button onClick={() => setIsConfigModalOpen(true)} className="p-2 -mr-2 text-slate-400 hover:text-white"><Settings className="w-6 h-6" /></button>
         </div>
      </header>

      <main className="max-w-md mx-auto min-h-screen relative pt-[calc(4rem+env(safe-area-inset-top,20px))] px-4 pb-safe-area">
        {currentView === ViewState.DASHBOARD && renderDashboard()}
        {currentView === ViewState.WEBSITES && (
            <div className="pb-32 animate-fade-in pt-4">
                <div className="bg-slate-800 p-1 rounded-xl flex gap-1 mb-6">
                    <button onClick={() => setWebsiteSubTab('status')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-colors ${websiteSubTab === 'status' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400'}`}>Status</button>
                    <button onClick={() => setWebsiteSubTab('forms')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-colors ${websiteSubTab === 'forms' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-400'}`}>Formulários</button>
                </div>
                {websiteSubTab === 'status' ? sites.map(s => <MonitorCard key={s.id} site={s} onRefresh={() => {}} />) : forms.map(f => <InboxItem key={f.id} form={f} siteName={sites.find(s => s.id === f.siteId)?.name || 'Site'} onSelect={() => setSelectedFormId(f.id)} onDismiss={() => {}} />)}
            </div>
        )}
        {currentView === ViewState.NEWS && (
            <div className="pb-32 animate-fade-in pt-4 space-y-4">
                <h2 className="text-xl font-bold text-slate-100 mb-4 px-1">Notícias</h2>
                {newsArticles.map(article => <NewsCard key={article.id} article={article} />)}
            </div>
        )}
      </main>

      <SideMenu isOpen={isSideMenuOpen} onClose={() => setIsSideMenuOpen(false)} onNavigate={(v) => setCurrentView(v as ViewState)} onGenerateInsight={handleGenerateInsight} badges={{ forms: forms.filter(f => !f.isRead).length, emails: emails.filter(e => e.isUnread).length, trello: trelloCards.length }} />
      <ConfigModal isOpen={isConfigModalOpen} onClose={() => setIsConfigModalOpen(false)} preferences={dashPrefs} onTogglePreference={(k) => setDashPrefs(p => ({ ...p, [k]: !p[k as keyof typeof p] }))} onUpdateApiKey={() => {}} notificationsEnabled={false} onToggleNotifications={() => {}} locationEnabled={!weatherPermissionDenied} onToggleLocation={loadWeather} onReorderDashboard={(o) => setDashPrefs(p => ({ ...p, dashboardOrder: o }))} />
      <TabNav currentView={currentView} onChangeView={setCurrentView} badges={{ sites: sites.some(s => s.status === SiteStatus.OFFLINE), forms: forms.filter(f => !f.isRead).length, trello: trelloCards.length }} />

      {selectedFormId && <FormDetailsModal form={forms.find(f => f.id === selectedFormId)!} siteName={sites.find(s => s.id === forms.find(f => f.id === selectedFormId)?.siteId)?.name || 'Site'} onClose={() => setSelectedFormId(null)} />}
    </div>
  );
};

export default App;

