  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loadingWeather, setLoadingWeather] = useState(false);
  const [weatherPermissionDenied, setWeatherPermissionDenied] = useState(false);

  const [calendarIds, setCalendarIds] = usePersistedState<string[]>('monitor_calendar_ids_v10', [
      'hgmvbnhlrf4ufbjbg74m1sn004n9i34u@import.calendar.google.com'
  ]);
  const [calendarEvents, setCalendarEvents] = useState<CalendarEvent[]>([]);
  const [isLoadingCalendar, setIsLoadingCalendar] = useState(false);

  const [newsArticles, setNewsArticles] = useState<NewsArticle[]>([]);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [lastNewsFetch, setLastNewsFetch] = usePersistedState<number>('monitor_last_news_fetch_v10', 0);
