  const [isConfigModalOpen, setIsConfigModalOpen] = useState(false);

  const [dashPrefs, setDashPrefs] = usePersistedState<DashboardPrefs>('dashboard_prefs_v39', {
      showSites: true,
      showTrello: true,
      showGoogle: true,
