// Função para obter instância do AI de forma segura dentro do contexto da chamada
// Fix: Updated to use process.env.API_KEY directly in the constructor as per GenAI guidelines
const getAIClient = () => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY não configurada.");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const analyzeForms = async (forms: FormSubmission[]): Promise<string> => {
  try {
    const ai = getAIClient();

    const formSummary = forms.map(f => 
      `- De: ${f.senderName} | Mensagem: "${f.message}"`
    ).join('\n');

    const prompt = `
      Analise estas mensagens de formulário:
      ${formSummary}
      Resuma a urgência em português (máx 2 linhas).
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Análise indisponível.";
  } catch (error: any) {
    console.error("Erro Gemini Forms:", error);
    return `Erro IA: ${error.message}`;
  }
};

export const generateDashboardInsight = async (context: {
    sites: string[],
    forms: string[],
    emails: string[],
    trello: number,
    weather?: string
}): Promise<string> => {
    try {
        const ai = getAIClient();

        const siteText = context.sites?.length ? context.sites.join(', ') : "Todos online.";
        const formText = context.forms?.length ? context.forms.join('; ') : "Sem mensagens.";
        const weatherText = context.weather || "Clima desconhecido.";

        const prompt = `
        Atue como assistente executivo (Tidas).
        DADOS:
        - Clima: ${weatherText}
        - Sites: ${siteText}
        - Formulários Novos: ${formText}
        - Trello: ${context.trello} pendentes.

        INSTRUÇÃO:
        Crie um resumo de 3 linhas em Português sobre o estado geral do seu ecossistema. 
        Seja direto. Use emojis discretos.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });

        if (!response.text) {
            throw new Error("IA retornou resposta vazia.");
        }

        return response.text;
    } catch (error: any) {
        console.error("Erro detalhado Insight:", error);

        let message = error.message || error.toString();

        if (message.includes("API key") || message.includes("403")) {
            throw new Error("Erro de Chave API. Verifique as configurações.");
        }
        if (message.includes("fetch") || message.includes("Failed to fetch")) {
             throw new Error("Erro de conexão com o servidor da IA.");
        }
        if (message.includes("quota") || message.includes("429")) {
             throw new Error("Limite de uso da IA excedido.");
        }

        throw new Error(`Falha no Insight: ${message.substring(0, 50)}`);
    }
}

