    if (!('geolocation' in navigator)) return;
    setLoadingWeather(true);
    setWeatherPermissionDenied(false);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const [weatherData, locationName] = await Promise.all([
            fetchWeather(latitude, longitude),
            fetchLocationName(latitude, longitude)
          ]);
          if (weatherData) {
            setWeather({ ...weatherData, locationName });
          }
        } catch (e) {
          console.error("Erro ao carregar dados do clima:", e);
        } finally {
          setLoadingWeather(false);
        }
      },
      (error) => {
        setLoadingWeather(false);
        if (error.code === error.PERMISSION_DENIED) {
          setWeatherPermissionDenied(true);
        }
      },
      { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 } // Otimizado para celular
    );
